section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-suite-health-metrics-canon.json",
  "type": "object",
  "title": "QA Suite Health Metrics Canon",
  "required": [
    "canon_id",
    "metrics",
    "cadence_days",
    "report_window_days",
    "latest_report_path"
  ],
  "additionalProperties": false,
  "properties": {
    "canon_id": {
      "type": "string",
      "minLength": 1,
      "description": "Canon identifier."
    },
    "metrics": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Exactly 6 items: {id, threshold, direction \u2208 [lower_is_better, higher_is_better], owner, route_to_methodology}."
    },
    "cadence_days": {
      "type": "integer",
      "description": "Days between reports; ==7."
    },
    "report_window_days": {
      "type": "integer",
      "description": "Trailing window; \u22657."
    },
    "latest_report_path": {
      "type": "string",
      "minLength": 1,
      "description": "Path to the most recent committed report."
    }
  }
}
